import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";
import { LiveList, LiveMap, LiveObject } from "@liveblocks/client";

export type PollOption = LiveObject<{ id: string; label: string }>;
export type PollStorage = {
  poll: LiveObject<{
    question: string;
    options: LiveList<PollOption>;
  }>;
  votes: LiveMap<string, string>;
};

type Presence = Record<string, never>;

type UserMeta = {
  id: string;
  info: {
    name: string;
    color: string;
    role: "owner" | "voter";
  };
};

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

export const {
  RoomProvider,
  useRoom,
  useMyPresence,
  useUpdateMyPresence,
  useSelf,
  useOthers,
  useOthersMapped,
  useOthersConnectionIds,
  useOther,
  useBroadcastEvent,
  useEventListener,
  useErrorListener,
  useStorage,
  useObject,
  useMap,
  useList,
  useBatch,
  useHistory,
  useUndo,
  useRedo,
  useCanUndo,
  useCanRedo,
  useStorageRoot,
  useMutation,
  useStatus,
  useLostConnectionListener,
  useThreads,
  useUser,
  useCreateThread,
  useEditThreadMetadata,
  useCreateComment,
  useEditComment,
  useDeleteComment,
  useAddReaction,
  useRemoveReaction,
} = createRoomContext<Presence, PollStorage, UserMeta>(client);

export { LiveList, LiveMap, LiveObject };

import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

// Deterministic color palette keyed by userId
const COLORS = [
  "#E57373",
  "#81C784",
  "#64B5F6",
  "#FFD54F",
  "#BA68C8",
  "#4DB6AC",
  "#FF8A65",
  "#90A4AE",
];

function getColor(userId: string): string {
  let hash = 0;
  for (let i = 0; i < userId.length; i++) {
    hash = userId.charCodeAt(i) + ((hash << 5) - hash);
  }
  return COLORS[Math.abs(hash) % COLORS.length];
}

export async function POST(req: NextRequest) {
  const body = await req.json();
  const { userId, name } = body as { userId: string; name: string };

  const role: "owner" | "voter" = userId === "alice" ? "owner" : "voter";
  const color = getColor(userId);

  const { status, body: responseBody } = await liveblocks.identifyUser(
    { userId, groupIds: ["poll-room"] },
    { userInfo: { name, color, role } }
  );

  return new NextResponse(responseBody, {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

"use client";

import { Suspense, useCallback, useState } from "react";
import { useSearchParams } from "next/navigation";
import { LiveblocksProvider, ClientSideSuspense } from "@liveblocks/react/suspense";
import { LiveList, LiveMap, LiveObject } from "@liveblocks/client";
import {
  RoomProvider,
  useStorage,
  useMutation,
  useSelf,
} from "../liveblocks.config";

const ROOM_ID = `poll-room-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

// ─── Auth helper ────────────────────────────────────────────────────────────
function makeAuthEndpoint(userId: string, name: string) {
  return async (room: string) => {
    const res = await fetch("/api/liveblocks-auth", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, name, room }),
    });
    return res;
  };
}

// ─── Poll inner component (has access to Liveblocks hooks) ───────────────────
function PollInner() {
  const role = useSelf((me) => me.info.role);
  const self = useSelf((me) => me);

  const [newOptionLabel, setNewOptionLabel] = useState("");

  // ── Storage selectors ──────────────────────────────────────────────────────
  const question = useStorage((root) => root.poll.question);

  const options = useStorage((root) =>
    root.poll.options.map((opt) => ({ id: opt.id, label: opt.label }))
  );

  const votes = useStorage((root) => {
    const map: Record<string, string> = {};
    root.votes.forEach((optionId, userId) => {
      map[userId] = optionId;
    });
    return map;
  });

  // ── Derived tallies ────────────────────────────────────────────────────────
  const totalVotes = Object.keys(votes).length;

  function getPercentage(optionId: string): number {
    if (totalVotes === 0) return 0;
    const count = Object.values(votes).filter((v) => v === optionId).length;
    return Math.round((count / totalVotes) * 100);
  }

  const myVote = self ? votes[self.id] : undefined;

  // ── Mutations ──────────────────────────────────────────────────────────────
  const updateQuestion = useMutation(({ storage }, value: string) => {
    storage.get("poll").set("question", value);
  }, []);

  const addOption = useMutation(({ storage }, label: string) => {
    const id = crypto.randomUUID();
    const option = new LiveObject({ id, label });
    storage.get("poll").get("options").push(option);
  }, []);

  const removeOption = useMutation(({ storage }, optionId: string) => {
    const options = storage.get("poll").get("options");
    const idx = options.findIndex((o) => o.get("id") === optionId);
    if (idx !== -1) {
      options.delete(idx);
    }
    // Also remove votes for that option
    const votes = storage.get("votes");
    const toDelete: string[] = [];
    votes.forEach((votedOptionId, userId) => {
      if (votedOptionId === optionId) toDelete.push(userId);
    });
    toDelete.forEach((userId) => votes.delete(userId));
  }, []);

  const castVote = useMutation(({ storage, self }) => (optionId: string) => {
    storage.get("votes").set(self.id, optionId);
  }, []);

  // ── Handlers ───────────────────────────────────────────────────────────────
  const handleAddOption = useCallback(() => {
    const trimmed = newOptionLabel.trim();
    if (!trimmed) return;
    addOption(trimmed);
    setNewOptionLabel("");
  }, [newOptionLabel, addOption]);

  const isOwner = role === "owner";

  return (
    <main style={{ padding: 24, fontFamily: "system-ui", maxWidth: 600 }}>
      <h1>Liveblocks Collaborative Poll</h1>

      {/* Question */}
      <div style={{ marginBottom: 16 }}>
        <label>
          <strong>Question: </strong>
          <input
            data-testid="question-input"
            value={question ?? ""}
            onChange={(e) => isOwner && updateQuestion(e.target.value)}
            readOnly={!isOwner}
            disabled={!isOwner}
            style={{ width: "100%", fontSize: 16, padding: 4 }}
            placeholder="Enter poll question…"
          />
        </label>
      </div>

      {/* Owner-only: add option */}
      {isOwner && (
        <div style={{ marginBottom: 16, display: "flex", gap: 8 }}>
          <input
            data-testid="new-option-input"
            value={newOptionLabel}
            onChange={(e) => setNewOptionLabel(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleAddOption()}
            placeholder="New option label…"
            style={{ flex: 1, fontSize: 14, padding: 4 }}
          />
          <button data-testid="add-option-btn" onClick={handleAddOption}>
            Add option
          </button>
        </div>
      )}

      {/* Options list */}
      <ul style={{ listStyle: "none", padding: 0 }}>
        {options.map((opt) => {
          const pct = getPercentage(opt.id);
          const isVoted = myVote === opt.id;
          return (
            <li
              key={opt.id}
              style={{
                marginBottom: 12,
                padding: 8,
                border: "1px solid #ddd",
                borderRadius: 6,
                background: isVoted ? "#e8f5e9" : "#fff",
              }}
            >
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  marginBottom: 4,
                }}
              >
                {/* Label */}
                <span
                  data-testid={`label-${opt.id}`}
                  style={{ flex: 1, fontWeight: isVoted ? "bold" : "normal" }}
                >
                  {opt.label}
                </span>

                {/* Vote button */}
                <button
                  data-testid={`vote-${opt.id}`}
                  onClick={() => castVote(opt.id)}
                  style={{
                    background: isVoted ? "#4caf50" : "#1976d2",
                    color: "#fff",
                    border: "none",
                    borderRadius: 4,
                    padding: "4px 10px",
                    cursor: "pointer",
                  }}
                >
                  {isVoted ? "Voted" : "Vote"}
                </button>

                {/* Remove button (owner only) */}
                {isOwner && (
                  <button
                    data-testid={`remove-${opt.id}`}
                    onClick={() => removeOption(opt.id)}
                    style={{
                      background: "#e53935",
                      color: "#fff",
                      border: "none",
                      borderRadius: 4,
                      padding: "4px 10px",
                      cursor: "pointer",
                    }}
                  >
                    Remove
                  </button>
                )}
              </div>

              {/* Percentage bar */}
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div
                  style={{
                    flex: 1,
                    height: 8,
                    background: "#eee",
                    borderRadius: 4,
                    overflow: "hidden",
                  }}
                >
                  <div
                    style={{
                      width: `${pct}%`,
                      height: "100%",
                      background: "#1976d2",
                      transition: "width 0.3s",
                    }}
                  />
                </div>
                <span
                  data-testid={`bar-${opt.id}`}
                  style={{ minWidth: 36, textAlign: "right", fontSize: 13 }}
                >
                  {pct}%
                </span>
              </div>
            </li>
          );
        })}
      </ul>

      {/* Total votes */}
      <p data-testid="total-votes" style={{ fontWeight: "bold" }}>
        Total votes: {totalVotes}
      </p>
    </main>
  );
}

// ─── Room wrapper ────────────────────────────────────────────────────────────
function PollRoom() {
  return (
    <RoomProvider
      id={ROOM_ID}
      initialPresence={{}}
      initialStorage={{
        poll: new LiveObject({
          question: "",
          options: new LiveList([]),
        }),
        votes: new LiveMap([]),
      }}
    >
      <ClientSideSuspense fallback={<p>Connecting to room…</p>}>
        {() => <PollInner />}
      </ClientSideSuspense>
    </RoomProvider>
  );
}

// ─── Page wrapper (reads query params, mounts providers) ─────────────────────
function PollPageContent() {
  const searchParams = useSearchParams();
  const userId = searchParams.get("userId") ?? "anonymous";
  const name = searchParams.get("name") ?? userId;

  return (
    <LiveblocksProvider authEndpoint={makeAuthEndpoint(userId, name)}>
      <PollRoom />
    </LiveblocksProvider>
  );
}

export default function PollPage() {
  return (
    <Suspense fallback={<p>Loading…</p>}>
      <PollPageContent />
    </Suspense>
  );
}

