                border: "1px solid #ddd",
                borderRadius: 6,
                background: isVoted ? "#e8f5e9" : "#fff",
              }}
            >
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 8,
                  marginBottom: 4,
                }}
              >
                {/* Label */}
                <span
                  data-testid={`label-${opt.id}`}
                  style={{ flex: 1, fontWeight: isVoted ? "bold" : "normal" }}
                >
                  {opt.label}
                </span>

                {/* Vote button */}
                <button
                  data-testid={`vote-${opt.id}`}
                  onClick={() => castVote(opt.id)}
                  style={{
                    background: isVoted ? "#4caf50" : "#1976d2",
                    color: "#fff",
                    border: "none",
                    borderRadius: 4,
                    padding: "4px 10px",
                    cursor: "pointer",
                  }}
                >
                  {isVoted ? "Voted" : "Vote"}
                </button>

                {/* Remove button (owner only) */}
                {isOwner && (
                  <button
                    data-testid={`remove-${opt.id}`}
                    onClick={() => removeOption(opt.id)}
                    style={{
                      background: "#e53935",
                      color: "#fff",
                      border: "none",
                      borderRadius: 4,
                      padding: "4px 10px",
                      cursor: "pointer",
                    }}
                  >
                    Remove
                  </button>
                )}
              </div>

              {/* Percentage bar */}
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div
                  style={{
                    flex: 1,
                    height: 8,
                    background: "#eee",
                    borderRadius: 4,
                    overflow: "hidden",
                  }}
                >
                  <div
                    style={{
                      width: `${pct}%`,
                      height: "100%",
                      background: "#1976d2",
                      transition: "width 0.3s",
                    }}
                  />
                </div>
                <span
                  data-testid={`bar-${opt.id}`}
                  style={{ minWidth: 36, textAlign: "right", fontSize: 13 }}
                >
                  {pct}%
                </span>
              </div>
            </li>
          );
        })}
      </ul>

      {/* Total votes */}
      <p data-testid="total-votes" style={{ fontWeight: "bold" }}>
        Total votes: {totalVotes}
      </p>
    </main>
  );
}

// ─── Room wrapper ────────────────────────────────────────────────────────────
function PollRoom() {
  return (
    <RoomProviderSuspense
      id={ROOM_ID}
      initialPresence={{}}
      initialStorage={{
        poll: new LiveObject({
          question: "",
          options: new LiveList([]),
        }),
        votes: new LiveMap([]),
      }}
    >
      <ClientSideSuspense fallback={<p>Connecting to room…</p>}>
        {() => <PollInner />}
      </ClientSideSuspense>
    </RoomProviderSuspense>
  );
}

// ─── Page content (reads query params, sets userRef, mounts room) ────────────
function PollPageContent() {
  const searchParams = useSearchParams();
  const userId = searchParams.get("userId") ?? "anonymous";
  const name = searchParams.get("name") ?? userId;

  // Set user identity before the room provider mounts
  userRef.userId = userId;
  userRef.name = name;

  return <PollRoom />;
}

// ─── Default export ──────────────────────────────────────────────────────────
export default function PollPage() {
  return (
    <Suspense fallback={<p>Loading…</p>}>
      <PollPageContent />
    </Suspense>
  );
}
